{"Question": "How do I handle data from different sources (DataFrame vs Database)?", "Context": "I want to use the same selection logic whether my data comes from a pandas DataFrame or a database table.", "Code_Example": "from selectpipe import SelectPipe, Select, select_numeric, select_strings
from app.core.engine import Engine

# Function that works with any data source
def analyze_customer_data(data_source, is_dataframe=True):
    if is_dataframe:
        # Initialize with DataFrame
        pipeline = SelectPipe.from_dataframe(data_source)
    else:
        # Initialize with database engine
        engine, table_name = data_source
        pipeline = SelectPipe.from_engine(engine, table_name)

    # Apply same selection logic regardless of source
    processed = (pipeline 
        | Select('customer_id', 'name', 'email')
        | select_numeric()  # Add all numeric columns
        | select_strings()  # Add all string columns
    )

    # Get results
    if is_dataframe:
        return processed.to_df()
    else:
        return processed.to_df(fetch_data=True)

